def build_universal_questions(state_name, regulator_title, guaranty_name,
                               ce_hours, course_label):
    reg = regulator_title
    guar = guaranty_name
    st = state_name
    return [
        (f"Who is primarily responsible for regulating the insurance industry in {st}?",
         "multiple_choice", "standard",
         f"The {reg} is the chief insurance regulator in {st}, responsible for licensing producers, approving policy forms and rates, and enforcing state insurance laws.",
         [(f"The {reg}", True, f"Correct. The {reg} has broad authority to regulate all aspects of insurance in {st}."),
          ("The federal Department of Insurance", False, "There is no federal Department of Insurance. Insurance regulation is primarily a state function under the McCarran-Ferguson Act."),
          ("The National Association of Insurance Commissioners (NAIC)", False, "The NAIC is a standard-setting body without direct regulatory authority."),
          ("The state attorney general", False, "The attorney general handles legal matters but the insurance regulator has primary jurisdiction.")]),

        (f"Under {st} law, which of the following is misrepresentation by an insurance producer?",
         "multiple_choice", "standard",
         "Misrepresentation is an unfair trade practice that includes making false or misleading statements about policy terms, benefits, or conditions.",
         [("Telling a client a policy covers losses it does not actually cover", True, "Correct. Making false statements about coverage is misrepresentation — a prohibited unfair trade practice."),
          ("Explaining differences between two competing policies accurately", False, "Accurate explanations are legitimate sales practice, not misrepresentation."),
          ("Recommending a policy based on the client's stated financial needs", False, "Recommending suitable coverage is proper producer duty."),
          ("Delivering a policy within the time required by state law", False, "Timely delivery is an obligation, not a prohibited practice.")]),

        (f"In {st}, rebating is best defined as:",
         "multiple_choice", "standard",
         "Rebating is offering or giving any valuable consideration as an inducement to purchase insurance, which is prohibited because it undermines filed rate integrity.",
         [("Offering anything of value as an inducement to purchase insurance", True, "Correct. Rebating is giving valuable consideration to induce an insurance purchase."),
          ("Charging a client more than the filed premium rate", False, "Overcharging is not rebating."),
          ("Replacing one policy with another without the client's consent", False, "Replacement through misrepresentation is twisting."),
          ("Splitting a commission with another licensed producer", False, "Commission sharing between licensed producers is generally permitted.")]),

        (f"A {st} producer who uses misrepresentation to persuade a policyholder to cancel an existing policy and buy a new one is guilty of:",
         "multiple_choice", "standard",
         "Twisting is using misrepresentation to induce a policyholder to replace an existing policy — a prohibited unfair trade practice in all states.",
         [("Twisting", True, "Correct. Using misrepresentation to induce policy replacement is twisting."),
          ("Rebating", False, "Rebating involves giving value as an inducement, not misrepresentation to replace."),
          ("Defamation", False, "Defamation is making false statements about another insurer or producer."),
          ("Churning", False, "Churning is replacement within the same company primarily for commission.")]),

        (f"Under {st} insurance law, a producer's license may be suspended or revoked for:",
         "multiple_choice", "standard",
         "Misappropriation of client premiums is a serious fiduciary violation and grounds for license suspension or revocation.",
         [("Misappropriating client premium funds", True, "Correct. Misappropriating premiums is grounds for license action in every state."),
          ("Failing the licensing exam on the first attempt", False, "Failing an exam is not grounds for license discipline."),
          ("Selling only one type of insurance product", False, "Specializing is not a violation."),
          ("Recommending a competitor's product to a client", False, "Recommending a competitor's product is not prohibited.")]),

        (f"In {st}, when a licensed producer collects a premium payment from a client, those funds are:",
         "multiple_choice", "standard",
         "Premium funds collected by a producer are fiduciary property that must be held separately from the producer's own money.",
         [("Fiduciary funds that must be held separately from the producer's own money", True, "Correct. Collected premiums are fiduciary funds that must not be commingled."),
          ("The producer's personal income until transmitted to the insurer", False, "Premiums are never the producer's personal income."),
          ("Subject to a producer's lien until earned commissions are deducted", False, "Producers cannot retain premiums as a lien."),
          ("Unclaimed until the policy is formally issued", False, "Premiums must be held as fiduciary property immediately upon collection.")]),

        (f"The purpose of {st}'s insurance guaranty association is to:",
         "multiple_choice", "standard",
         f"The {guar} protects policyholders when a licensed insurer becomes insolvent, paying claims up to statutory limits.",
         [("Pay covered claims when a licensed insurer becomes insolvent", True, f"Correct. The {guar} pays covered claims when a licensed insurer is declared insolvent."),
          ("Regulate insurance rates to keep premiums affordable", False, "Rate regulation is the regulator's function, not the guaranty association's."),
          ("Provide reinsurance to small insurance companies", False, "Reinsurance is a private market function."),
          ("Manage the state's high-risk insurance pool", False, "High-risk pools are separate mechanisms from the guaranty association.")]),

        (f"Under {st} law, when a producer wants to replace a client's existing life policy with a new one, the producer must:",
         "multiple_choice", "standard",
         "Replacement regulations require written comparison disclosures and notification to the existing insurer.",
         [("Provide a written comparison disclosure and notify the existing insurer", True, "Correct. Replacement requires comparison disclosures to the client and notification to the existing insurer."),
          ("Obtain written approval from the state insurance department", False, "State approval is not required for individual replacements."),
          ("Cancel the existing policy before placing the new policy", False, "The new policy should be in place before cancelling the existing one to avoid a coverage gap."),
          ("Charge no commission on the replacement policy", False, "Commission restrictions are not a standard replacement requirement.")]),

        (f"In {st}, a nonresident producer licensed in another state generally:",
         "multiple_choice", "standard",
         "Most states grant nonresident licenses by reciprocity without a separate exam for producers in good standing in their home state.",
         [("May be issued a nonresident license without a state exam if their home state offers reciprocity", True, "Correct. Reciprocity allows nonresident producers to skip the exam if their home state is reciprocal."),
          ("Must take and pass the full state licensing exam regardless of home state license", False, "Most states waive the exam for reciprocal nonresident applicants."),
          ("Must establish a business office in the state before receiving a license", False, "Nonresident producers are not required to maintain a physical office."),
          ("Is exempt from all continuing education requirements in the nonresident state", False, "CE may still be required for nonresident producers.")]),

        (f"In {st}, which of the following constitutes coercion in the sale of insurance?",
         "multiple_choice", "standard",
         "Coercion is using threats, force, or economic pressure to compel someone to purchase insurance — a prohibited unfair trade practice.",
         [("Threatening to cancel a client's business contract unless they purchase insurance through you", True, "Correct. Economic threats to compel an insurance purchase is coercion."),
          ("Recommending a specific insurer based on financial strength ratings", False, "Recommending based on objective criteria is legitimate."),
          ("Explaining the penalties for driving without required auto insurance", False, "Explaining legal requirements is not coercion."),
          ("Offering a client a choice between two policy options", False, "Offering choices is standard sales practice.")]),

        (f"A {st} insurance producer's license must be renewed every:",
         "multiple_choice", "standard",
         "Most states require biennial license renewal with continuing education as a condition.",
         [("Two years, with continuing education requirements", True, f"Correct. Most states including {st} require biennial renewal with required CE."),
          ("One year, without any continuing education requirement", False, "Annual renewal without CE is not the standard."),
          ("Five years, with no exam required at renewal", False, "5-year renewal cycles are not standard."),
          ("There is no renewal requirement once a license is issued", False, "All state licenses require periodic renewal and CE.")]),

        (f"Under {st} law, a temporary insurance license may be issued to:",
         "multiple_choice", "standard",
         "Temporary licenses are most commonly issued to allow agency continuity after the licensed producer's death or incapacitation.",
         [("A surviving spouse or family member to continue an agency after the licensed producer's death", True, "Correct. Temporary licenses most commonly allow agency continuity after the licensed owner's death."),
          ("Any person who applies for a license while waiting for exam results", False, "Waiting for exam results does not qualify for a temporary license."),
          ("A person who failed the exam and needs time to retake it", False, "Exam failure does not qualify for a temporary license."),
          ("Any unlicensed employee of an insurance agency", False, "Being employed by an agency does not automatically qualify for a temporary license.")]),

        (f"In {st}, express authority of an insurance producer is best described as:",
         "multiple_choice", "standard",
         "Express authority is explicitly granted in writing through the agency agreement between the producer and the insurer.",
         [("Authority specifically granted in the written agency agreement", True, "Correct. Express authority is stated explicitly in the written contract."),
          ("Authority arising from the producer's position and normal business customs", False, "Authority from position and custom is implied authority."),
          ("Authority created when a third party reasonably believes the producer has authority based on the insurer's conduct", False, "This is apparent authority."),
          ("Authority the producer assumes without any written agreement", False, "Assumed authority without agreement is not a recognized type of authority.")]),

        (f"Under {st} insurance law, defamation by a producer is:",
         "multiple_choice", "standard",
         "Defamation is making false statements about another insurer or producer that injure their reputation. Truth is a complete defense.",
         [("Making false statements that injure the reputation of another insurer or producer", True, "Correct. Defamation requires false statements; truthful statements are not defamation."),
          ("Accurately reporting a competitor's financial difficulties to a client", False, "Truthful statements are not defamation."),
          ("Failing to disclose a material fact about a policy", False, "Failure to disclose is misrepresentation by omission, not defamation."),
          ("Using intimidation to prevent a client from shopping other insurers", False, "Intimidation is coercion, not defamation.")]),
    ]


def build_semi_universal(state_name, regulator_title, guaranty_name,
                          ce_hours, course_label):
    st = state_name
    reg = regulator_title
    return [
        (f"A {st} producer who moves must notify the {reg} within:",
         "multiple_choice", "standard",
         "Most states require producers to notify the regulator of address changes within 30 days.",
         [("30 days of the address change", True, "Correct. Most states require notification within 30 days."),
          ("5 business days", False, "Shorter than the standard requirement."),
          ("60 days", False, "Exceeds the typical requirement."),
          ("At the next license renewal", False, "Changes must be reported promptly, not deferred to renewal.")]),

        (f"In {st}, continuing education for licensed producers typically includes:",
         "multiple_choice", "standard",
         "Most states require CE hours per renewal cycle including a required ethics component.",
         [("A specified number of hours including an ethics component", True, "Correct. Most states require a minimum number of CE hours with a mandatory ethics component."),
          ("Only product knowledge courses with no ethics requirement", False, "Ethics is a required component in virtually all states."),
          ("CE is optional — only required if a complaint was filed", False, "CE is a mandatory renewal requirement for all producers."),
          ("A state exam retake every renewal cycle", False, "Retaking the exam is not a CE requirement.")]),

        (f"Under {st} law, a producer convicted of a felony must:",
         "multiple_choice", "standard",
         "Most states require producers to report felony convictions to the insurance regulator within a specified timeframe.",
         [("Report the conviction to the state insurance regulator within the required timeframe", True, "Correct. Most states require prompt reporting of felony convictions."),
          ("Immediately surrender their license without any hearing", False, "A conviction triggers reporting requirements and may lead to a hearing, not automatic surrender."),
          ("Only report if the conviction relates to financial crimes", False, "Most states require reporting all felony convictions."),
          ("Wait until the conviction is final before reporting", False, "Most states require reporting upon conviction.")]),

        (f"In {st}, which entity must approve advertising materials before a producer uses them?",
         "multiple_choice", "standard",
         "The insurer must review and approve advertising materials used by its producers to ensure compliance with state regulations.",
         [("The insurer the producer represents", True, "Correct. The insurer must approve producer advertising materials for regulatory compliance."),
          ("The state insurance department must pre-approve all advertisements", False, "Pre-approval by the state is not required for most lines."),
          ("A national advertising standards board", False, "No such national board exists for insurance."),
          ("No approval is needed", False, "Insurance advertising is regulated; insurer approval is typically required.")]),

        (f"The {guaranty_name} covers claims when:",
         "multiple_choice", "standard",
         "The guaranty association covers claims only from licensed admitted insurer insolvencies — not unlicensed insurer failures.",
         [("A licensed admitted insurer is declared insolvent", True, "Correct. The guaranty association covers claims from licensed insurer insolvencies."),
          ("A claim is denied by any insurer for any reason", False, "The guaranty association only covers insolvency situations."),
          ("A policyholder cannot afford to pay their premium", False, "Premium affordability is not a guaranty association trigger."),
          ("An unauthorized insurer fails to pay claims", False, "Only licensed admitted insurer failures are covered.")]),

        (f"Under {st} law, sharing a commission with an unlicensed person:",
         "multiple_choice", "standard",
         "Sharing commissions with unlicensed individuals is prohibited and grounds for license discipline in all states.",
         [("Violates state insurance law and may result in license suspension or revocation", True, "Correct. Sharing commissions with unlicensed persons is prohibited."),
          ("Is permitted if the unlicensed person performed legitimate services", False, "Services performed do not authorize commission sharing with unlicensed persons."),
          ("Must be reported to the state insurance department", False, "The arrangement is prohibited; disclosure does not make it permissible."),
          ("Is only permitted for family members", False, "Family relationships do not create an exception.")]),
    ]


